        }
    }

    // Draw Outer Board Border
    ctx.strokeStyle = OUTLINE_COLOR;
    ctx.lineWidth = 5;
    ctx.strokeRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);
}
