```javascript
// Helper function for Rook moves (Based on Q6)
function calculatePseudoMoves(piece, sourceR, sourceC) {
    const moves = [];
    const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]]; // Up, Down, Left, Right

    for (const [dR, dC] of directions) {
        let R_curr = sourceR + dR;
        let C_curr = sourceC + dC;
        while (R_curr >= 0 && R_curr < BOARD_SIZE && C_curr >= 0 && C_curr < BOARD_SIZE) {
            const targetPiece = board[R_curr][C_curr];

            // 1. Add the target square to moves
            moves.push({ row: R_curr, col: C_curr });

            // 2. Block checking: If the target square is occupied, stop searching in this line
            if (targetPiece) {
                break;
            }

            // 3. Continue in the same direction
            R_curr += dR;
            C_curr += dC;
        }
    }
    return moves;
}

